const users6h = $('Fetch New Users 6h').first().json.users || [];
const users24h = $('Fetch New Users 24h').first().json.users || [];
const users48h = $('Fetch New Users 48h').first().json.users || [];
const users72h = $('Fetch New Users 72h').first().json.users || [];

const seen = new Set();
const allUsers = [];

for (const u of users6h) {
  if (!seen.has(u.telegram_id)) {
    seen.add(u.telegram_id);
    allUsers.push({ ...u, stage: 'welcome' });
  }
}
for (const u of users24h) {
  if (!seen.has(u.telegram_id)) {
    seen.add(u.telegram_id);
    allUsers.push({ ...u, stage: 'signals' });
  }
}
for (const u of users48h) {
  if (!seen.has(u.telegram_id)) {
    seen.add(u.telegram_id);
    allUsers.push({ ...u, stage: 'accuracy' });
  }
}
for (const u of users72h) {
  if (!seen.has(u.telegram_id)) {
    seen.add(u.telegram_id);
    allUsers.push({ ...u, stage: 'referral' });
  }
}

return [{ json: { users: allUsers, count: allUsers.length } }];

const users = $json.users || [];
const items = [];

const stagePrompts = {
  welcome: (u) => `Write a warm welcome DM for a new user named ${u.first_name || 'there'}. Introduce Griffin Gold — an AI-powered Gold prediction platform. Mention the /predict command to get started and that they have a free trial. Make it feel personal and exciting.`,
  signals: (u) => `Write a follow-up DM for ${u.first_name || 'there'} who joined ~24h ago. Introduce the /signal command — explain that Griffin Gold sends real-time trading signals based on AI analysis. Encourage them to try it and see what the AI recommends.`,
  accuracy: (u) => `Write a DM for ${u.first_name || 'there'} who has been using Griffin Gold for ~2 days. Introduce the /accuracy command — show that Griffin Gold is transparent about its prediction track record, including misses. Build trust through honesty.`,
  referral: (u) => `Write a DM for ${u.first_name || 'there'} who has been with Griffin Gold for ~3 days. Introduce the /referral program — when they refer a friend, BOTH get +7 days of Premium access for free. Make it feel like a win-win.`
};

for (const user of users) {
  const promptFn = stagePrompts[user.stage];
  if (!promptFn) continue;
  items.push({
    json: {
      telegram_id: user.telegram_id,
      first_name: user.first_name || 'there',
      stage: user.stage,
      prompt: promptFn(user)
    }
  });
}

return items;

