const users24h = $('Fetch Trial Expiry 24h').first().json.users || [];
const users6h = $('Fetch Trial Expiry 6h').first().json.users || [];
const users1h = $('Fetch Trial Expiry 1h').first().json.users || [];

const seen = new Set();
const allUsers = [];

// Highest urgency first so they get the most urgent tier
for (const u of users1h) {
  if (!seen.has(u.telegram_id)) {
    seen.add(u.telegram_id);
    allUsers.push({ ...u, tier: 'lastchance' });
  }
}
for (const u of users6h) {
  if (!seen.has(u.telegram_id)) {
    seen.add(u.telegram_id);
    allUsers.push({ ...u, tier: 'warning' });
  }
}
for (const u of users24h) {
  if (!seen.has(u.telegram_id)) {
    seen.add(u.telegram_id);
    allUsers.push({ ...u, tier: 'gentle' });
  }
}

return [{ json: { users: allUsers, count: allUsers.length } }];

const users = $json.users || [];
const items = [];

const tierPrompts = {
  gentle: (u) => `Write a casual, friendly DM for ${u.first_name || 'there'} whose Griffin Gold Premium trial expires tomorrow. Gently remind them of the value they've been getting — AI predictions, signals, accuracy tracking. Don't be pushy. Just highlight what they'll keep with Premium.`,
  warning: (u) => `Write an urgent but respectful DM for ${u.first_name || 'there'} whose Premium trial expires in 6 hours. Show what they'll lose: real-time signals, advanced predictions, accuracy stats. Mention there may be a discount available for upgrading now.`,
  lastchance: (u) => `Write a final-chance DM for ${u.first_name || 'there'} whose Premium trial expires in under 1 hour. Create urgency — this is their last chance to lock in Premium before losing access. Mention a limited-time offer. Make them feel they'd miss out.`
};

for (const user of users) {
  const promptFn = tierPrompts[user.tier];
  if (!promptFn) continue;
  items.push({
    json: {
      telegram_id: user.telegram_id,
      first_name: user.first_name || 'there',
      tier: user.tier,
      prompt: promptFn(user)
    }
  });
}

return items;

